import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { Package, Plus, X, Search } from 'lucide-react';

function PartnerProducts() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [buyerEmail, setBuyerEmail] = useState('');
  const [notes, setNotes] = useState('');
  const [blockingError, setBlockingError] = useState('');
  const [creating, setCreating] = useState(false);

  useEffect(() => {
    loadProducts();
  }, []);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const response = await partnerService.getProducts();
      setProducts(response.data);
    } catch (error) {
      console.error('Error loading products:', error);
    } finally {
      setLoading(false);
    }
  };

  const openSaleModal = (product) => {
    setSelectedProduct(product);
    setBuyerEmail('');
    setNotes('');
    setBlockingError('');
    setShowSaleModal(true);
  };

  const closeSaleModal = () => {
    setShowSaleModal(false);
    setSelectedProduct(null);
    setBuyerEmail('');
    setNotes('');
    setBlockingError('');
  };

  // Check if buyer can purchase when email changes
  useEffect(() => {
    const checkBuyerEligibility = async () => {
      // Clear error when email is empty or being typed
      if (!buyerEmail || !buyerEmail.includes('@')) {
        setBlockingError('');
        return;
      }

      if (!selectedProduct) return;

      try {
        // Check in existing buyers first
        const buyersResponse = await partnerService.getBuyers();
        const existingBuyer = buyersResponse.data.find(
          b => b.email.toLowerCase() === buyerEmail.toLowerCase()
        );

        if (existingBuyer) {
          // Check if this buyer already purchased this product
          const canSellResponse = await partnerService.canSellToBuyer(
            selectedProduct.productId,
            existingBuyer.userId
          );

          if (!canSellResponse.data.canSell) {
            setBlockingError('This buyer has already purchased this product from another partner');
          } else {
            setBlockingError('');
          }
        } else {
          // New buyer - always allowed
          setBlockingError('');
        }
      } catch (error) {
        console.error('Error checking buyer eligibility:', error);
        setBlockingError('');
      }
    };

    // Debounce the check
    const timer = setTimeout(checkBuyerEligibility, 500);
    return () => clearTimeout(timer);
  }, [buyerEmail, selectedProduct]);

  const handleCreateSale = async (e) => {
    e.preventDefault();

    if (!buyerEmail || !buyerEmail.includes('@')) {
      alert('Please enter a valid buyer email');
      return;
    }

    if (blockingError) {
      alert(blockingError);
      return;
    }

    try {
      setCreating(true);

      // First, check if buyer exists in the system
      const buyersResponse = await partnerService.getBuyers();
      let buyerId = null;

      const existingBuyer = buyersResponse.data.find(
        b => b.email.toLowerCase() === buyerEmail.toLowerCase()
      );

      if (existingBuyer) {
        buyerId = existingBuyer.userId;
      } else {
        // Create new buyer with minimal info
        // Since there's no register endpoint for buyers, we'll create a basic user
        const newBuyerData = {
          fullName: buyerEmail.split('@')[0], // Use email prefix as name
          email: buyerEmail,
          password: 'TempPassword@123', // Temporary password
          userRole: 'Buyer',
          phoneNumber: '',
          companyName: '',
          address: ''
        };

        const registerResponse = await fetch('http://localhost:5261/api/auth/register', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(newBuyerData)
        });

        if (!registerResponse.ok) {
          throw new Error('Failed to create buyer');
        }

        const newBuyer = await registerResponse.json();
        buyerId = newBuyer.userId;
      }

      // Create the sale
      const saleData = {
        productId: selectedProduct.productId,
        buyerId: buyerId,
        notes: notes
      };

      await partnerService.createSale(saleData);

      alert('Sale created successfully!');
      closeSaleModal();
      loadProducts();
    } catch (error) {
      console.error('Error creating sale:', error);
      alert(error.response?.data?.message || 'Failed to create sale');
    } finally {
      setCreating(false);
    }
  };

  const formatCurrency = (amount) => {
    return `₹${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '400px' }}>
        <p style={{ fontSize: '1.2rem', color: '#666' }}>Loading products...</p>
      </div>
    );
  }

  return (
    <div style={{ padding: '2rem' }}>
      <div style={{ marginBottom: '2rem' }}>
        <h1 style={{ fontSize: '2rem', color: '#333', marginBottom: '0.5rem' }}>Available Products</h1>
        <p style={{ color: '#666' }}>Browse and sell products to earn commission</p>
      </div>

      {/* Products Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
        gap: '1.5rem'
      }}>
        {products.map((product) => (
          <div key={product.productId} style={{
            background: 'white',
            borderRadius: '12px',
            padding: '1.5rem',
            boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
            border: '1px solid #e5e7eb',
            transition: 'transform 0.2s, box-shadow 0.2s',
            cursor: 'pointer'
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = 'translateY(-4px)';
            e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.15)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = '0 2px 8px rgba(0,0,0,0.1)';
          }}>
            <div style={{ display: 'flex', alignItems: 'flex-start', gap: '1rem', marginBottom: '1rem' }}>
              <div style={{
                width: '48px',
                height: '48px',
                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                borderRadius: '12px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0
              }}>
                <Package size={24} color="white" />
              </div>
              <div style={{ flex: 1 }}>
                <h3 style={{ fontSize: '1.25rem', fontWeight: '600', color: '#111', marginBottom: '0.25rem' }}>
                  {product.productName}
                </h3>
                <p style={{ fontSize: '1.5rem', fontWeight: '700', color: '#667eea', margin: 0 }}>
                  {formatCurrency(product.price)}
                </p>
              </div>
            </div>

            <p style={{ color: '#666', fontSize: '0.9rem', marginBottom: '1rem', lineHeight: '1.5' }}>
              {product.description}
            </p>

            <div style={{
              background: '#f9fafb',
              borderRadius: '8px',
              padding: '1rem',
              marginBottom: '1rem'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                <span style={{ color: '#666', fontSize: '0.875rem' }}>Admin:</span>
                <span style={{ fontWeight: '600', color: '#111', fontSize: '0.875rem' }}>{product.adminName || 'N/A'}</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                <span style={{ color: '#666', fontSize: '0.875rem' }}>Commission:</span>
                <span style={{ fontWeight: '600', color: '#10b981', fontSize: '0.875rem' }}>{product.commissionPercentage}%</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ color: '#666', fontSize: '0.875rem' }}>You Earn:</span>
                <span style={{ fontWeight: '700', color: '#10b981', fontSize: '1rem' }}>
                  {formatCurrency(product.price * (product.commissionPercentage / 100))}
                </span>
              </div>
            </div>

            <button
              onClick={() => openSaleModal(product)}
              style={{
                width: '100%',
                padding: '0.75rem',
                background: '#667eea',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                fontSize: '1rem',
                fontWeight: '600',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '0.5rem',
                transition: 'background 0.2s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.background = '#5568d3'}
              onMouseLeave={(e) => e.currentTarget.style.background = '#667eea'}
            >
              <Plus size={20} />
              Create Sale
            </button>
          </div>
        ))}
      </div>

      {products.length === 0 && (
        <div style={{
          textAlign: 'center',
          padding: '4rem 2rem',
          color: '#999'
        }}>
          <Package size={64} color="#ccc" style={{ marginBottom: '1rem' }} />
          <h3 style={{ fontSize: '1.5rem', color: '#666', marginBottom: '0.5rem' }}>No Products Available</h3>
          <p>There are no products available for sale at the moment.</p>
        </div>
      )}

      {/* Sale Modal */}
      {showSaleModal && selectedProduct && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'rgba(0,0,0,0.5)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000,
          padding: '1rem'
        }} onClick={closeSaleModal}>
          <div style={{
            background: 'white',
            borderRadius: '12px',
            padding: '2rem',
            maxWidth: '500px',
            width: '100%',
            maxHeight: '90vh',
            overflowY: 'auto'
          }} onClick={(e) => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
              <h2 style={{ fontSize: '1.5rem', color: '#111', margin: 0 }}>
                Create Sale - {selectedProduct.productName}
              </h2>
              <button onClick={closeSaleModal} style={{
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                padding: '0.5rem',
                borderRadius: '4px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center'
              }}>
                <X size={24} color="#666" />
              </button>
            </div>

            {/* Blocking Error Alert - Only shows when email is valid and blocked */}
            {blockingError && buyerEmail && (
              <div style={{
                background: '#fee',
                border: '1px solid #fcc',
                color: '#c33',
                padding: '0.75rem 1rem',
                borderRadius: '8px',
                marginBottom: '1rem',
                fontSize: '0.9rem'
              }}>
                {blockingError}
              </div>
            )}

            <div style={{
              background: '#f9fafb',
              borderRadius: '8px',
              padding: '1rem',
              marginBottom: '1.5rem'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                <span style={{ color: '#666' }}>Price:</span>
                <span style={{ fontWeight: '700', color: '#10b981', fontSize: '1.25rem' }}>
                  {formatCurrency(selectedProduct.price)}
                </span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ color: '#666' }}>Your Commission ({selectedProduct.commissionPercentage}%):</span>
                <span style={{ fontWeight: '700', color: '#10b981', fontSize: '1.25rem' }}>
                  {formatCurrency(selectedProduct.price * (selectedProduct.commissionPercentage / 100))}
                </span>
              </div>
            </div>

            <form onSubmit={handleCreateSale}>
              <div style={{ marginBottom: '1.5rem' }}>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600', color: '#333' }}>
                  Buyer Email *
                </label>
                <div style={{ position: 'relative' }}>
                  <Search size={20} color="#999" style={{
                    position: 'absolute',
                    left: '1rem',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    pointerEvents: 'none'
                  }} />
                  <input
                    type="email"
                    value={buyerEmail}
                    onChange={(e) => setBuyerEmail(e.target.value)}
                    placeholder="Enter buyer email (any email allowed)..."
                    required
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem 0.75rem 3rem',
                      border: blockingError && buyerEmail ? '1px solid #f87171' : '1px solid #d1d5db',
                      borderRadius: '8px',
                      fontSize: '1rem',
                      outline: 'none',
                      transition: 'border-color 0.2s'
                    }}
                    onFocus={(e) => {
                      if (!blockingError) e.target.style.borderColor = '#667eea';
                    }}
                    onBlur={(e) => {
                      if (!blockingError) e.target.style.borderColor = '#d1d5db';
                    }}
                  />
                </div>
                <p style={{ fontSize: '0.75rem', color: '#999', marginTop: '0.25rem' }}>
                  Enter any email address. New buyers will be created automatically.
                </p>
              </div>

              <div style={{ marginBottom: '1.5rem' }}>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '600', color: '#333' }}>
                  Notes (Optional)
                </label>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Add any notes about this sale..."
                  rows={4}
                  style={{
                    width: '100%',
                    padding: '0.75rem',
                    border: '1px solid #d1d5db',
                    borderRadius: '8px',
                    fontSize: '1rem',
                    outline: 'none',
                    resize: 'vertical',
                    fontFamily: 'inherit'
                  }}
                  onFocus={(e) => e.target.style.borderColor = '#667eea'}
                  onBlur={(e) => e.target.style.borderColor = '#d1d5db'}
                />
              </div>

              <div style={{ display: 'flex', gap: '1rem' }}>
                <button
                  type="button"
                  onClick={closeSaleModal}
                  style={{
                    flex: 1,
                    padding: '0.75rem',
                    background: 'white',
                    color: '#666',
                    border: '1px solid #d1d5db',
                    borderRadius: '8px',
                    fontSize: '1rem',
                    fontWeight: '600',
                    cursor: 'pointer'
                  }}
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={creating || !!blockingError}
                  style={{
                    flex: 1,
                    padding: '0.75rem',
                    background: (creating || blockingError) ? '#ccc' : '#667eea',
                    color: 'white',
                    border: 'none',
                    borderRadius: '8px',
                    fontSize: '1rem',
                    fontWeight: '600',
                    cursor: (creating || blockingError) ? 'not-allowed' : 'pointer'
                  }}
                >
                  {creating ? 'Creating...' : 'Create Sale'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default PartnerProducts;
